BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?contained ?containedName ?containedType WHERE {
  {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::Signals::APS%2520External::PEAS-CommonService>
      vocab:Element_ownedElement+ ?contained .
  }
  UNION
  {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::Signals::APS%2520External::PEAS-CommonService>
      vocab:Package_packagedElement+ ?contained .
  }
  UNION
  {
    <http://api.koneksys.com/cameo/TMT/package/TMT::Project::Work%2520Packages::Telescope::WorkPackages::Control::Alignment%2520and%2520Phasing%2520System::Systems%2520Engineering::01%2520Components::Operational::APS::Conceptual%2520Design::Signals::APS%2520External::PEAS-CommonService>
      vocab:Namespace_ownedMember+ ?contained .
  }
  ?contained rdf:type ?containedType .
  OPTIONAL { ?contained vocab:NamedElement_name ?containedName . }
  FILTER(
    ?containedType = vocab:signal ||
    ?containedType = vocab:Signal
  )
}
ORDER BY ?containedName
LIMIT 25

