BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?signal ?name ?qname WHERE {
  ?signal rdf:type vocab:signal .
  OPTIONAL { ?signal vocab:NamedElement_name ?name . }
  OPTIONAL { ?signal vocab:NamedElement_namespace ?ns . }
  OPTIONAL { ?ns vocab:NamedElement_name ?qname . }
  FILTER(
    (BOUND(?name) && CONTAINS(LCASE(STR(?name)), LCASE("PEAS-CommonService")))
    || (BOUND(?qname) && CONTAINS(LCASE(STR(?qname)), LCASE("PEAS-CommonService")))
    || CONTAINS(LCASE(STR(?signal)), LCASE("PEAS-CommonService"))
  )
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?signal ?name WHERE {
  ?signal rdf:type vocab:signal .
  OPTIONAL { ?signal vocab:NamedElement_name ?name }

  {
    ?signal vocab:NamedElement_namespace ?ns .
    ?ns vocab:NamedElement_name ?nsName .
    FILTER(CONTAINS(LCASE(STR(?nsName)), LCASE("PEAS-CommonService")))
  }
  UNION
  {
    ?signal vocab:NamedElement_namespace ?ns2 .
    FILTER(CONTAINS(LCASE(STR(?ns2)), LCASE("PEAS-CommonService")))
  }
}
ORDER BY ?name
LIMIT 25
